INSERT INTO "public"."companies" ("id", "trading_name", "companies_house_name", "url", "url_linkedin", "description", "policy", "open_to_sponsorship", "active_jobs_count", "url_favicon", "licensed_sponsor", "estimated_num_employees_label", "created_at", "updated_at", "ats_provider", "ats_board_token", "linkedin_id") VALUES ('1', 'incident.io', 'Pineapple Technology Ltd', 'https://incident.io/', 'https://www.linkedin.com/company/incident-io/', 'incident.io is a technology company founded in 2021, specializing in an all-in-one incident management platform. Headquartered in New York City, with additional locations in London and San Francisco, the company focuses on helping engineering and site reliability teams manage and resolve incidents efficiently, primarily through integration with Slack.

The platform streamlines incident response by allowing organizations to announce incidents in a single Slack channel in a consistent format. It unifies key functions such as on-call scheduling, real-time incident response, and integrated status pages, providing a comprehensive toolset for managing operational disruptions. incident.io emphasizes customizability, enabling teams to tailor workflows and forms to enhance the incident resolution process.

With a growing customer base that includes notable companies like Netflix, Linear, Ramp, and Etsy, incident.io has managed over 250,000 incidents since its inception. The company has raised over $96 million in funding, including a recent $62 million Series B round, reflecting strong investor confidence and supporting its continued growth in the incident management space.', 'The company can offer sponsorship for the majority of their roles in the UK.', '4', '0', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/292.png', 'true', 'Medium-sized company', '2026-03-03 15:44:04.042781+00', '2026-03-03 15:44:04.042781+00', null, null, null), ('2', 'VivaCity', 'Vivacity Labs Limited', 'https://vivacitylabs.com/', 'https://www.linkedin.com/company/vivacity-labs/', 'VivaCity, based in London, is a technology company founded in 2015 that specializes in AI-powered traffic and transportation monitoring solutions. The company aims to make cities smarter, safer, and more sustainable by providing data-driven insights to help governments and local councils optimize urban transport infrastructure.

VivaCity offers a range of AI-driven sensor technologies and software solutions for smart traffic monitoring and road safety. Their Viva Sensors capture accurate, anonymized multimodal transportation data around the clock, delivering real-time insights into vehicle and pedestrian movements, traffic flow, and near-miss incidents. This information supports proactive road safety initiatives and helps transportation decision-makers enhance road usage and urban planning.

The company primarily serves government agencies, regional transportation bodies, and local councils, providing them with the tools needed to improve traffic management and support sustainable urban development. With a dedicated team of experts, VivaCity is committed to embedding AI at the heart of transport networks worldwide.', 'The company is a licensed sponsor.', '4', '0', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/1214.png', 'true', 'Medium-sized company', '2026-03-03 15:44:04.042781+00', '2026-03-03 15:44:04.042781+00', 'lever', 'vivacitylabs', null), ('3', 'Robin AI', 'Robin AI Limited', 'https://www.robinai.com', 'https://www.linkedin.com/company/robinai/', 'Robin AI is a legal technology company that specializes in artificial intelligence solutions aimed at enhancing legal workflows, particularly in contract review and management. Founded by Richard Robinson and Dr. James Clough, the company focuses on automating repetitive tasks to improve the efficiency of legal professionals without replacing them.

The core product, an AI-powered contract review tool, enables lawyers to complete contract reviews up to 80% faster while maintaining accuracy. It suggests edits and highlights key information, allowing lawyers to retain control over final decisions. Additionally, Robin AI offers a legal AI assistant that supports various functions, including drafting contracts and researching case law. The company is also integrating its solutions with practice management platforms to serve small and mid-sized law firms effectively.

With a commitment to data security and compliance, Robin AI is trusted by a diverse range of clients, including large corporations and prestigious law firms. Since its launch in 2019, the company has raised over $44 million in funding and aims to build a comprehensive AI platform to support legal professionals in all aspects of their work.', 'The company is open to providing visa sponsorship.', '1', '1', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/323.png', 'true', 'Medium-sized company', '2026-03-03 15:44:03.25189+00', '2026-03-03 15:44:03.25189+00', null, null, null), ('4', 'Faculty', 'Faculty Science Limited', 'https://faculty.ai/', 'https://www.linkedin.com/company/facultyai/', 'Faculty is a British artificial intelligence company founded in 2014 and based in London. Initially starting as a fellowship program for PhD graduates, it has grown into a prominent applied AI firm focused on delivering impactful solutions across various industries. The company aims to harness AI to solve complex problems and improve business performance and public sector outcomes.

Faculty offers a range of services, including custom AI model development, data science consulting, and AI-driven decision support tools. Their solutions address areas such as risk management and investment optimization in finance, predictive analytics in healthcare, and policy formulation in government. Faculty collaborates with institutions like UCL and Harvard University to promote the ethical deployment of AI.

With around 300 employees and approximately $42.5 million in funding, Faculty serves a diverse clientele, including corporations, government agencies, and educational institutions. Their work emphasizes ethical AI use and societal impact, driving innovation and efficiency in finance, healthcare, government, and education sectors.', 'Sponsorship can be offered for some roles.', '3', '64', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/11.png', 'true', 'Large company', '2026-03-03 15:44:01.557015+00', '2026-03-03 15:44:01.557015+00', 'ashby', 'https://api.ashbyhq.com/posting-api/job-board/faculty', null), ('5', 'Ensek', null, 'https://ensek.teamtailor.com/jobs/', 'https://www.linkedin.com/company/ensek/', null, null, null, '0', null, 'true', null, '2026-03-04 15:19:16.324222+00', '2026-03-04 15:19:16.324222+00', 'teamtailor', 'ensek', null), ('6', 'Net Scientific', null, 'https://netscientific.bamboohr.com/careers', 'https://www.linkedin.com/company/net-scientific/', null, null, null, '1', null, 'true', null, '2026-03-04 15:19:16.470392+00', '2026-03-04 15:19:16.470392+00', 'bamboohr', 'netscientific', null), ('7', 'eGym', null, 'https://egym.jobs.personio.de/', 'https://www.linkedin.com/company/egym/', null, null, null, '0', null, 'true', null, '2026-03-04 15:19:16.628911+00', '2026-03-04 15:19:16.628911+00', 'personio', 'egym', null), ('8', 'Productboard', 'Productboard UK Ltd', 'https://www.productboard.com/', 'https://www.linkedin.com/company/productboard/', 'Productboard is a product management software company founded in 2014 by Hubert Palan and Daniel Hejl. With offices in cities like San Francisco, Vancouver, and Dublin, and a remote team across Europe, Productboard has grown into a globally recognized entity. The company is backed by notable Silicon Valley venture capital firms and has been featured on Forbes’ Next Billion-Dollar Startups list.

The core offering of Productboard is a centralized product management platform that helps teams streamline their product development processes. It allows users to prioritize features, gather customer insights, and align product roadmaps with business goals. The platform operates on a seat-based subscription model with three user roles: Makers, Contributors, and Viewers, and offers tiered plans—Essentials, Pro, and Enterprise. A recent innovation, Productboard Pulse, is an AI-powered solution for enhancing customer feedback analysis. With over 6,000 customers, Productboard is dedicated to helping product teams create user-centered products that meet real needs.', 'The company is a licensed sponsor.', '4', '0', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/544.png', 'true', 'Large company', '2026-03-03 15:44:03.25189+00', '2026-03-03 15:44:03.25189+00', 'smartrecruiters', 'productboard', null), ('9', 'Collibra', 'Collibra UK Ltd', 'https://www.collibra.com/', 'https://www.linkedin.com/company/collibra/', 'Collibra is a data intelligence company founded in 2008 in Brussels, Belgium, and now headquartered in New York City. With over 1,000 employees, Collibra''s mission is to help organizations unlock the value of their data, enabling efficient access and understanding to support data-driven decision-making.

The company offers a range of solutions, including the Data Governance Center, which helps manage data assets and ensure compliance, and the Data Intelligence Platform, a cloud-based tool that connects IT and business users. Their Data Catalog allows enterprises to discover and organize data assets, while their AI Governance tools manage and govern AI models. Collibra partners with companies like Snowflake to provide integrated data governance solutions.

Collibra serves a diverse array of global enterprises, particularly in financial services, where regulatory compliance is crucial. The company has experienced significant growth, raising over $295 million in funding and achieving unicorn status with a valuation exceeding $1 billion by 2019.', 'Sponsorship cannot be offered currently.', '2', '3', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/289.png', 'true', 'Large company', '2026-03-03 15:44:00.376782+00', '2026-03-03 15:44:00.376782+00', 'greenhouse', 'collibra', null), ('10', 'Verto', 'Vertofx Ltd', 'https://www.vertofx.com/', 'https://www.linkedin.com/company/vertofx/', 'Verto is a London-based fintech company that specializes in cross-border B2B payments and foreign exchange (FX) solutions, focusing on emerging markets, particularly in Africa. Founded in 2017 and operating under an Electronic Money Institution (EMI) license from the UK''s Financial Conduct Authority, Verto ensures high regulatory standards and secure handling of customer funds.

The company offers a range of services designed to streamline global financial operations for businesses. This includes a cross-border payments platform, multi-currency wallets, and a liquidity marketplace that connects businesses with competitive FX rates. Verto also provides expense management tools, FX and treasury management solutions, and a core API for seamless integration with financial systems. With a team of around 170 employees, Verto serves over 1,000 customers, helping them manage millions in cross-border transactions efficiently and effectively.', 'The company is a licensed sponsor.', '4', '3', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/210.png', 'true', 'Medium-sized company', '2026-03-03 15:44:04.042781+00', '2026-03-03 15:44:04.042781+00', 'bamboohr', 'verto', null), ('11', 'Sylvera', 'Sylvera Ltd', 'https://www.sylvera.com/', 'https://www.linkedin.com/company/sylveracarbon/', 'Sylvera is a climate technology company focused on promoting investment in effective climate action. They provide independent and transparent evaluations of carbon projects that capture, remove, or avoid greenhouse gas emissions. Their mission is to assist organizations in achieving net zero emissions through software that automates the assessment of carbon credit projects with scientific rigor.

The company utilizes advanced data collection methods, including LiDAR technology and satellite data, to gather over 450 billion data points. This extensive data infrastructure supports precise carbon accounting and project evaluation. Sylvera offers carbon credit ratings based on peer-reviewed frameworks, a centralized carbon market platform with access to over 20,000 projects, and market insights to help businesses navigate carbon markets. They also engage in research and collaboration with various stakeholders to enhance understanding of nature-based solutions.

With offices in London, New York, and Singapore, Sylvera serves a global clientele, including businesses and governments, providing reliable insights to support their climate strategies and investments in carbon markets.', 'The company is a licensed sponsor.', '4', '5', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/402.png', 'true', 'Medium-sized company', '2026-03-03 15:44:03.25189+00', '2026-03-03 15:44:03.25189+00', 'lever', 'sylvera', null), ('12', 'Teya', 'Teya Services Ltd', 'https://teya.com/', 'https://www.linkedin.com/company/teya-global/?originalSubdomain=uk', 'Teya is a financial technology company based in London, specializing in all-in-one card payment solutions for small and medium-sized businesses (SMBs) across Europe. Founded in 2019 and previously known as SaltPay, Teya has quickly established itself as a leading provider of payment processing services in the EU. The company is authorized by the UK Financial Conduct Authority, ensuring compliance and security in its offerings.

Teya''s core products include next-generation card machines, integrated business banking services, and transparent payment processing with flat-rate pricing for Visa and Mastercard transactions. The company also provides business tools and analytics for real-time sales tracking, along with flexible payment options to enhance cash flow management. Teya focuses on empowering local merchants and service providers by streamlining payment acceptance and financial management, supported by strong customer service available through various channels.', 'The company is a licensed sponsor.', '4', '81', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/509.png', 'true', 'Very large company', '2026-03-03 15:44:04.042781+00', '2026-03-03 15:44:04.042781+00', 'ashby', 'https://api.ashbyhq.com/posting-api/job-board/teya', null), ('13', 'Pledge', 'Pledge Earth Technologies Ltd', 'https://www.pledge.io/', 'https://www.linkedin.com/company/pledge-app/', 'Pledge is a London-based startup founded in 2021 that offers a software platform designed to help businesses in freight forwarding, ride-hailing, travel, and last-mile delivery manage and reduce their carbon emissions, particularly Scope 3 emissions. The company focuses on providing tools for emissions measurement, analytics, and offsetting, enabling enterprises and logistics service providers to take effective climate action.

The platform allows businesses to calculate their logistics-related carbon footprints, track supplier data, and purchase carbon offsets. It is tailored for logistics service providers and shippers, offering solutions that simplify complex climate data and support sustainable procurement practices. Pledge aims to turn sustainability into a competitive advantage for its clients.

Recently, Pledge underwent a brand refresh to emphasize its commitment to sustainability and was acquired by Blue Yonder, enhancing its capabilities in helping businesses achieve their emissions reduction and sustainability targets.', 'Sponsorship can be offered for some roles.', '1', '0', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/10.png', 'true', 'Small company', '2026-03-03 15:44:03.25189+00', '2026-03-03 15:44:03.25189+00', null, null, null), ('14', 'Wheely', 'Wheely Technologies Ltd', 'https://wheely.com/', 'https://www.linkedin.com/company/wheely/?originalSubdomain=uk', 'Wheely is a luxury vehicle-for-hire company founded in Switzerland and based in London. It specializes in chauffeur-driven journeys, operating in major cities like London, Paris, and Dubai, with plans for expansion into the US. The company caters to affluent customers looking for a personalized and discreet transportation experience.

Wheely offers a luxury ride-hailing platform through iOS and Android apps, allowing users to book rides on-demand or in advance. The service features three main classes of luxury vehicles, including models from Mercedes-Benz and exclusive options like Wheely Luxe. All chauffeurs are trained through Wheely’s in-house Chauffeur Academy, which emphasizes safety, etiquette, and discretion. The company employs a time and distance pricing model without surge pricing, ensuring a transparent and reliable service. Additionally, Wheely provides a concierge service through its app, allowing chauffeurs to assist with personal tasks beyond transportation.', 'The company is a licensed sponsor.', '3', '23', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/1162.png', 'true', 'Large company', '2026-03-03 15:44:04.042781+00', '2026-03-03 15:44:04.042781+00', 'greenhouse', 'wheely', null), ('15', 'Robinhood', 'Robinhood U.K. Ltd', 'https://robinhood.com/', 'https://www.linkedin.com/company/robinhood/', 'Robinhood Markets, Inc. is a fintech company and registered broker-dealer founded in 2013 by Vladimir Tenev and Baiju Bhatt, with its headquarters in Menlo Park, California. The company aims to democratize finance by providing commission-free access to financial markets for everyone, not just the wealthy. Robinhood''s mobile and web app allows users to trade stocks, options, exchange-traded funds (ETFs), and cryptocurrencies without incurring trading fees.

In addition to its trading platform, Robinhood offers banking services with FDIC insurance, wealth management services that include personalized financial planning, and educational content through initiatives like "Sherwood News" and the rebranded newsletter "Snacks." The company has expanded internationally, launching services in the UK and obtaining a brokerage license in Lithuania. Robinhood primarily generates revenue through payment for order flow, premium subscriptions, and interest on uninvested cash balances. It targets retail investors, particularly younger individuals seeking accessible and low-cost trading options.', 'The company is a licensed sponsor.', '3', '4', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/249.png', 'true', 'Very large company', '2026-03-03 15:44:03.25189+00', '2026-03-03 15:44:03.25189+00', 'greenhouse', 'robinhood', null), ('16', 'Trilitech', 'Trilitech Limited', 'https://www.trili.tech/', 'https://www.linkedin.com/company/trilitech/', 'Trilitech is a London-based blockchain research and development company founded in 2021. It specializes in the open-source Tezos blockchain platform and operates as a private limited company. The company focuses on business and domestic software development, aiming to advance the Web3 revolution through innovative blockchain solutions in sectors like Culture, Decentralized Finance (DeFi), and Gaming.

Trilitech provides custom blockchain development solutions and entrepreneurial programs to foster innovation within the blockchain ecosystem. It collaborates with notable global partners, including Manchester United, McLaren Racing, and Ubisoft, to deliver projects that integrate blockchain technology with mainstream industries. With a workforce of approximately 51-200 employees, Trilitech promotes a dynamic work culture that emphasizes innovation, agility, and strong communication, supporting flexible working arrangements and professional development.', 'The company is a licensed sponsor.', '3', '4', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/250.png', 'true', 'Medium-sized company', '2026-03-03 15:44:04.042781+00', '2026-03-03 15:44:04.042781+00', null, null, null), ('17', 'Wayve', 'Wayve Technologies Ltd', 'https://wayve.ai/', 'https://www.linkedin.com/company/wayve-technologies/', 'Wayve is a UK-based technology company founded in 2017, specializing in autonomous driving solutions using Embodied AI. Headquartered in London, Wayve develops AI foundation models that enable vehicles to learn from and interact with real-world environments, focusing on urban mobility and complex city navigation.

The company''s core technology, AV2.0, utilizes a single neural network trained on diverse raw sensor data, allowing for mapless autonomy and adaptability to new geographies. This vehicle-agnostic technology can operate on various vehicle types, from passenger cars to delivery vans. Wayve emphasizes safe and scalable driving automation, with AI models designed to handle unexpected driving scenarios effectively.

Wayve has raised over $1.3 billion in funding, including a significant $1.05 billion Series C round, with support from major investors like SoftBank Group, NVIDIA, and Microsoft. The company operates globally, with offices in the UK, United States, Canada, Germany, Japan, and Israel, and collaborates with automotive OEMs to integrate advanced autonomous driving technology into production vehicles.', 'The company offers sponsorship and relocation support for many of their roles.', '4', '16', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/352.png', 'true', 'Large company', '2026-03-03 15:44:04.042781+00', '2026-03-03 15:44:04.042781+00', 'greenhouse', 'wayve', null), ('18', 'Equiniti', 'Equiniti Limited', 'https://equiniti.wd3.myworkdayjobs.com/en-US/Opportunities', 'https://www.linkedin.com/company/equiniti/', null, null, null, '36', 'https://equiniti.com/favicon.ico', 'true', null, '2026-03-04 15:25:41.264333+00', '2026-03-04 15:25:41.264333+00', 'workday', 'equiniti/Opportunities', null), ('19', 'Porsche', 'Porsche Cars GB Ltd.', 'https://www.porsche.com/international/', 'https://www.linkedin.com/company/porsche-ag/', 'Porsche AG is a prominent German automobile manufacturer based in Stuttgart, specializing in luxury, high-performance sports cars, SUVs, and sedans. Founded in 1931 by Ferdinand Porsche, the company initially started as a design and engineering consultancy before becoming a full-fledged car manufacturer. Porsche is celebrated for its iconic models, particularly the Porsche 911, which has been a symbol of sports car excellence since its introduction in 1964.

As part of the Volkswagen Group, Porsche offers a diverse product lineup that includes the legendary 911, the Boxster, the Cayman, and luxury SUVs like the Cayenne and Macan. The Panamera serves as a luxury four-door sports sedan, while the Taycan represents Porsche''s commitment to electric mobility. Additionally, Porsche Engineering Group GmbH provides advanced engineering services across various industries, showcasing the company''s expertise in automotive design and innovative technologies.

Porsche targets affluent customers who value luxury, performance, and cutting-edge technology. With a strong global presence, the brand appeals to sports car enthusiasts and buyers of high-end electric vehicles, leveraging its rich motorsport heritage to enhance its prestige.', 'The company is not currently offering visa sponsorship.', '2', '0', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/491.png', 'true', 'Very large company', '2026-03-03 15:44:03.25189+00', '2026-03-03 15:44:03.25189+00', 'smartrecruiters', 'porsche', null), ('20', 'Winton', 'Winton Capital Management Ltd', 'https://www.winton.com/', 'https://www.linkedin.com/company/winton/', 'Winton is a global quantitative investment management firm founded in 1997 and based in London. The company specializes in designing and managing portfolios of quantitative investment strategies that trade across major liquid asset classes worldwide. With a team of over 190 professionals, Winton operates across four continents, allowing for close client relationships and regional market expertise.

Winton offers multi-strategy quantitative investment management services, focusing on algorithm-driven investment strategies that adapt to various market environments. Their proprietary technology and infrastructure support the entire process from idea generation to live trading. The firm serves a diverse client base, including large institutional investors and financial advisers, emphasizing collaboration and methodological rigor to deliver consistent returns across different market conditions. Winton is also committed to responsible business practices, supporting initiatives that address global challenges through profits from their investment activities.', 'The company is a licensed sponsor.', '4', '9', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/1163.png', 'true', 'Medium-sized company', '2026-03-03 15:44:04.042781+00', '2026-03-03 15:44:04.042781+00', 'greenhouse', 'winton', null), ('21', 'FranklinCovey', 'FranklinCovey Europe Limited', 'https://www.franklincovey.com/', 'https://www.linkedin.com/company/franklincovey/', 'FranklinCovey is a global leader in leadership and organizational performance, offering business consulting, talent development, education, and training services. Founded in 1983, the company emerged from a merger between Franklin Institute and Covey Leadership Center in 1997, blending time management systems with the principles of Stephen R. Covey’s *7 Habits of Highly Effective People*.

The company provides a range of services, including training seminars and workshops focused on leadership development and culture transformation. It also offers time management tools like the Franklin Planner, along with books, audio programs, and software based on its productivity principles. FranklinCovey''s consulting services assist organizations in implementing behavioral change and fostering performance cultures. The company serves a diverse clientele, including many Fortune 100 and Fortune 500 companies, government agencies, and educational institutions, and it has a strong presence with sales offices on four continents and over 130 retail stores worldwide.', 'The company is a licensed sponsor.', '4', '0', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/858.png', 'true', 'Very large company', '2026-03-03 15:44:01.557015+00', '2026-03-03 15:44:01.557015+00', null, null, null), ('22', 'Bird', 'MessageBird UK Limited', 'https://bird.com/', 'https://www.linkedin.com/company/birdhq/', 'Bird is a company that specializes in electric vehicle-sharing services, offering shared electric scooters and bikes for urban transportation. Headquartered in Santa Monica, California, Bird operates through an online platform that allows users to rent lightweight electric vehicles conveniently.

The company provides a range of electric scooters and bikes, including models like Bird Three and Bird Bikeshare. Bird also partners with fleet managers and operators to efficiently deploy and manage fleets of electric vehicles. Its platform includes features for fleet management, real-time data monitoring, and regulatory compliance, ensuring a smooth experience for both users and operators.

Bird aims to serve urban communities worldwide, providing eco-friendly transportation solutions for individuals and collaborating with city operators to enhance shared mobility.', 'The company is a licensed sponsor.', '3', '1', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/40.png', 'true', 'Large company', '2026-03-03 15:44:00.376782+00', '2026-03-03 15:44:00.376782+00', 'greenhouse', 'bird', null), ('23', 'LoopMe', 'LoopMe Ltd', 'https://loopme.com/', 'https://www.linkedin.com/company/loopme/', 'LoopMe is a technology company based in the UK, founded in 2012, that focuses on AI-powered brand advertising and digital media optimization. The company helps brand marketers enhance their advertising effectiveness across various digital channels, including mobile in-app video, gaming, connected TV, digital audio, and digital out-of-home. Its platform utilizes artificial intelligence and data science to optimize media campaigns in real-time, resulting in improved purchase intent, brand consideration, foot traffic, and sales growth.

With a global presence, LoopMe has offices in major cities such as New York, San Francisco, Singapore, Tokyo, Sydney, and Hong Kong. The company employs over 200 people and has shown strong growth, reporting estimated gross revenues near $100 million in 2021. LoopMe''s offerings include an AI-driven advertising platform, an Audience and Measurement Platform (AMP), and cross-channel media optimization, which collectively serve a diverse range of clients, including well-known global brands and advertising agencies. The company is committed to innovation and customer satisfaction, aiming to enhance consumer experiences through its advanced technology.', 'The company is a licensed sponsor.', '3', '2', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/147.png', 'true', 'Large company', '2026-03-03 15:44:02.529791+00', '2026-03-03 15:44:02.529791+00', 'workable', 'loopme', null), ('24', 'Astroscale', 'Astroscale Ltd', 'https://astroscale.com/', 'https://www.linkedin.com/company/astroscale/', 'Astroscale is a global leader in on-orbit servicing, dedicated to ensuring the safe and sustainable development of space. Founded in 2013 and based in Tokyo, Japan, the company addresses critical challenges such as space debris and satellite life extension. Astroscale develops innovative solutions for various missions, including extending satellite lifespans, monitoring space traffic, safely deorbiting satellites, and actively removing space debris.

The company provides flexible, end-to-end services that encompass mission licensing, spectrum acquisition, insurance, and operational support. Astroscale aims to create a sustainable space environment by reducing collision risks and preserving orbital infrastructure, which is essential for the expanding space economy. Their diverse customer base includes government and defense agencies like NASA and the U.S. Space Force, as well as commercial satellite operators and international space stakeholders. With subsidiaries in the UK, the US, Israel, and Singapore, Astroscale plays a significant role in international space discussions and initiatives.', 'The company is a licensed sponsor.', '4', '5', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/1086.png', 'true', 'Large company', '2026-03-03 15:44:00.376782+00', '2026-03-03 15:44:00.376782+00', 'bamboohr', 'astroscale', null), ('25', 'Second Home', 'Second Home Ltd', 'https://secondhome.io/', 'https://www.linkedin.com/company/second-home/', 'Second Home is a British social business that promotes entrepreneurship, creativity, and innovation in urban areas around the world. Established in 2014, it operates distinctive workspaces and cultural venues designed to nurture creative communities. The first location opened in East London, followed by sites including a bookshop called Libreria, a school building in Nairobi, and a vibrant workspace in Lisbon’s historic market. The architectural designs of these spaces, primarily by SelgasCano and DOSIS, integrate nature to create inspiring environments.

Second Home provides innovative coworking spaces that serve as hubs for entrepreneurs, startups, and creative professionals. Their venues also host events, talks, and community activities to encourage collaboration and cultural exchange. The company is committed to social impact, as seen in its educational projects and its focus on supporting creative economies and urban regeneration. With a total funding of $34.9 million, Second Home continues to expand its reach into new cities globally.', 'The company is a licensed sponsor.', '4', '0', 'https://jbuikhbssecxhfunkaol.supabase.co/storage/v1/object/public/company_icons/505.png', 'true', 'Medium-sized company', '2026-03-03 15:44:03.25189+00', '2026-03-03 15:44:03.25189+00', 'breezy', 'second', null), ('26', 'Changing Social', 'Changing Social Ltd', 'https://www.changingsocial.com/', 'https://www.linkedin.com/company/changing-social/', 'Changing Social is a Bristol-based consultancy founded in 2016, specializing in information technology consultancy with a focus on Microsoft technology adoption and change management. As a people-first Microsoft Partner, the company helps organizations maximize their investments in Microsoft 365 and related technologies through effective change management processes.

